#ifndef ALGORITHM_MINIMUMWINDOWSUBSTRING_H
#define ALGORITHM_MINIMUMWINDOWSUBSTRING_H
#include <iostream>
#include <ostream>
#include <string>
#include <unordered_map>

#include "../../../Solution.h"

class MinimumWindowSubstring: public Solution {
public:
    inline bool isQualified(const std::unordered_map<char, int>& map) {
        for (const auto& it: map) {
            if (it.second < 0) return false;
        }
        return true;
    }

    std::string minWindow(std::string s, std::string t) {
        if (s.length() < t.length()) { return ""; }

        std::unordered_map<char, int> map;
        int charInT[128] = {0};
        for (char c: t) {
            map[c]--;
            charInT[c] = 1;
        }

        int start = 0, end = 0;
        int bestL = 0, bestLen = INT_MAX;
        std::string result;

        while (end < s.length()) {

            // move end
            if (!isQualified(map)) {
                // 如果end所指字符，不曾出现在t中，则不对map操作
                char c = s[end];
                if (charInT[s[end]] != 0) {
                    map[s[end]]++;
                    if (map[s[end]] == 0) {
                        map.erase(s[end]);
                    }
                }
            }
            while (isQualified(map)) {
                int len = end - start + 1;
                if (len < bestLen) { bestLen = len; bestL = start; }
                if (charInT[s[start]] != 0) {
                    map[s[start]]--;
                    if (map[s[start]] == 0) {
                        map.erase(s[start]);
                    }
                }
                start++;
            }
            end++;

        }
        return bestLen == INT_MAX ? "" : s.substr(bestL, bestLen);
    }

    virtual void main() override {
        std::string s = "";
        std::string t = "aAbBcCdDeEfFgGhHiIjJkKlLmMnNoOpPqQrRsStTuUvVwWxXyYzZ";
        std::cout << minWindow(s, t) << std::endl;
    }
};

#endif //ALGORITHM_MINIMUMWINDOWSUBSTRING_H